这个是一个html的标注代码，那么导入文件对比，文件应该如何命名才可以让它们自动对比？
<!DOCTYPE html>
<html lang="zh-CN">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>本地数据标记工具</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
        }
        body {
            background-color: #f5f7fa;
            color: #333;
            height: 100vh;
            display: flex;
            flex-direction: column;
        }
        /* 顶部控制栏 */
        .header {
            background-color: #2c3e50;
            color: white;
            padding: 12px 20px;
            display: flex;
            justify-content: space-between;
            align-items: center;
            box-shadow: 0 2px 5px rgba(0,0,0,0.1);
            z-index: 100;
        }
        .logo {
            font-size: 1.5rem;
            font-weight: bold;
        }
        .controls {
            display: flex;
            gap: 15px;
            align-items: center;
        }
        .btn {
            padding: 8px 16px;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: 500;
            transition: all 0.2s;
        }
        .btn-primary {
            background-color: #3498db;
            color: white;
        }
        .btn-primary:hover {
            background-color: #2980b9;
        }
        .btn-success {
            background-color: #2ecc71;
            color: white;
        }
        .btn-success:hover {
            background-color: #27ae60;
        }
        .btn-warning {
            background-color: #f39c12;
            color: white;
        }
        .btn-warning:hover {
            background-color: #d35400;
        }
        .btn-danger {
            background-color: #e74c3c;
            color: white;
        }
        .btn-danger:hover {
            background-color: #c0392b;
        }
        .btn-info {
            background-color: #9b59b6;
            color: white;
        }
        .btn-info:hover {
            background-color: #8e44ad;
        }
        /* 进度条 */
        .progress-container {
            flex: 1;
            margin: 0 20px;
            background-color: #34495e;
            border-radius: 10px;
            height: 10px;
            overflow: hidden;
        }
        .progress-bar {
            height: 100%;
            background-color: #3498db;
            width: 0%;
            transition: width 0.3s;
        }
        .progress-text {
            font-size: 0.9rem;
            margin-left: 10px;
            min-width: 80px;
        }
        /* 主要内容区域 */
        .main-content {
            flex: 1;
            display: flex;
            overflow: hidden;
        }
        /* 侧边栏 */
        .sidebar {
            width: 250px;
            background-color: #34495e;
            color: white;
            overflow-y: auto;
            padding: 15px;
        }
        .folder-list {
            list-style: none;
        }
        .folder-item {
            padding: 10px 12px;
            margin-bottom: 5px;
            border-radius: 4px;
            cursor: pointer;
            transition: background-color 0.2s;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }
        .folder-item:hover {
            background-color: #3d566e;
        }
        .folder-item.active {
            background-color: #3498db;
        }
        .folder-status {
            width: 12px;
            height: 12px;
            border-radius: 50%;
        }
        .status-good {
            background-color: #2ecc71;
        }
        .status-fair {
            background-color: #f39c12;
        }
        .status-poor {
            background-color: #e74c3c;
        }
        .status-none {
            background-color: #95a5a6;
        }
        /* 文件显示区域 */
        .file-display {
            flex: 1;
            display: flex;
            overflow: hidden;
        }
        .file-panel {
            flex: 1;
            display: flex;
            flex-direction: column;
            border-right: 1px solid #ddd;
            background-color: white;
        }
        .file-panel:last-child {
            border-right: none;
        }
        .file-header {
            padding: 12px 15px;
            background-color: #ecf0f1;
            border-bottom: 1px solid #ddd;
            display: flex;
            justify-content: space-between;
            align-items: center;
        }
        .file-content {
            flex: 1;
            padding: 15px;
            overflow-y: auto;
        }
        .file-preview {
            width: 100%;
            height: 100%;
            border: none;
            background-color: white;
        }
        /* 标记按钮组 */
        .marking-buttons {
            display: flex;
            gap: 10px;
            padding: 15px;
            background-color: #ecf0f1;
            border-top: 1px solid #ddd;
        }
        .mark-btn {
            flex: 1;
            padding: 12px;
            border: none;
            border-radius: 4px;
            cursor: pointer;
            font-weight: 500;
            transition: all 0.2s;
        }
        .mark-btn.active {
            transform: scale(1.05);
            box-shadow: 0 3px 8px rgba(0,0,0,0.2);
        }
        /* 兼容性提示 */
        .compatibility-warning {
            background-color: #f39c12;
            color: white;
            padding: 10px 15px;
            text-align: center;
            display: none;
        }
        /* 加载指示器 */
        .loading {
            display: none;
            text-align: center;
            padding: 20px;
            color: #7f8c8d;
        }
        /* 响应式设计 */
        @media (max-width: 768px) {
            .main-content {
                flex-direction: column;
            }
            .sidebar {
                width: 100%;
                height: 200px;
            }
            .file-display {
                flex-direction: column;
            }
            .file-panel {
                height: 50%;
            }
            .controls {
                flex-wrap: wrap;
            }
            .progress-container {
                margin: 10px 0;
                order: 3;
                width: 100%;
            }
        }
    </style>
</head>
<body>
    <!-- 兼容性提示 -->
    <div class="compatibility-warning" id="compatibilityWarning">
        提示：此功能需要现代浏览器支持（Chrome/Edge 86+）。如果无法使用，请尝试更新浏览器。
    </div>
    <!-- 顶部控制栏 -->
    <div class="header">
        <div class="logo">数据标记工具</div>
        <div class="controls">
            <button class="btn btn-primary" id="loadBtn">选择根文件夹</button>
            <button class="btn btn-success" id="exportBtn">导出结果</button>
            <button class="btn btn-info" id="nextBtn">下一个 (N)</button>
            <div class="progress-container">
                <div class="progress-bar" id="progressBar"></div>
            </div>
            <div class="progress-text" id="progressText">0/0</div>
            <div class="current-folder">当前: <span id="currentFolder">未选择</span></div>
        </div>
    </div>
    <!-- 主要内容区域 -->
    <div class="main-content">
        <!-- 侧边栏 -->
        <div class="sidebar">
            <h3>文件夹列表</h3>
            <div class="loading" id="loadingIndicator">正在加载文件夹...</div>
            <ul class="folder-list" id="folderList">
                <!-- 文件夹列表将通过JavaScript动态生成 -->
            </ul>
        </div>
        <!-- 文件显示区域 -->
        <div class="file-display">
            <!-- 左侧文件 -->
            <div class="file-panel">
                <div class="file-header">
                    <span>文件1: <span id="fileName1">未选择</span></span>
                </div>
                <div class="file-content">
                    <iframe class="file-preview" id="preview1" src="about:blank"></iframe>
                </div>
            </div>
            <!-- 右侧文件 -->
            <div class="file-panel">
                <div class="file-header">
                    <span>文件2: <span id="fileName2">未选择</span></span>
                </div>
                <div class="file-content">
                    <iframe class="file-preview" id="preview2" src="about:blank"></iframe>
                </div>
            </div>
        </div>
    </div>
    <!-- 标记按钮组 -->
    <div class="marking-buttons">
        <button class="mark-btn btn-success" id="markGood">标记为 Good (G)</button>
        <button class="mark-btn btn-warning" id="markFair">标记为 Fair (F)</button>
        <button class="mark-btn btn-danger" id="markPoor">标记为 Poor (P)</button>
        <button class="mark-btn btn-primary" id="skipBtn">跳过 (S)</button>
    </div>
    <script>
        // 存储标记结果
        let markings = {};
        let currentFolder = null;
        let folderList = [];
        let currentIndex = -1;
        let folderStructure = {};
        // DOM元素
        const folderListElement = document.getElementById('folderList');
        const currentFolderSpan = document.getElementById('currentFolder');
        const fileName1 = document.getElementById('fileName1');
        const fileName2 = document.getElementById('fileName2');
        const preview1 = document.getElementById('preview1');
        const preview2 = document.getElementById('preview2');
        const loadBtn = document.getElementById('loadBtn');
        const exportBtn = document.getElementById('exportBtn');
        const nextBtn = document.getElementById('nextBtn');
        const markGoodBtn = document.getElementById('markGood');
        const markFairBtn = document.getElementById('markFair');
        const markPoorBtn = document.getElementById('markPoor');
        const skipBtn = document.getElementById('skipBtn');
        const progressBar = document.getElementById('progressBar');
        const progressText = document.getElementById('progressText');
        const compatibilityWarning = document.getElementById('compatibilityWarning');
        const loadingIndicator = document.getElementById('loadingIndicator');
        // 检查浏览器兼容性
        function checkCompatibility() {
            if (!window.showDirectoryPicker) {
                compatibilityWarning.style.display = 'block';
                loadBtn.disabled = true;
                return false;
            }
            return true;
        }
        // 初始化
        function init() {
            // 检查兼容性
            checkCompatibility();
            // 绑定事件
            loadBtn.addEventListener('click', loadFolder);
            exportBtn.addEventListener('click', exportResults);
            nextBtn.addEventListener('click', nextFolder);
            markGoodBtn.addEventListener('click', () => markFolder('good'));
            markFairBtn.addEventListener('click', () => markFolder('fair'));
            markPoorBtn.addEventListener('click', () => markFolder('poor'));
            skipBtn.addEventListener('click', () => nextFolder());
            // 添加键盘快捷键
            document.addEventListener('keydown', handleKeyPress);
        }
        // 处理键盘快捷键
        function handleKeyPress(e) {
            if (!currentFolder) return;
            switch(e.key.toLowerCase()) {
                case 'g':
                    markFolder('good');
                    break;
                case 'f':
                    markFolder('fair');
                    break;
                case 'p':
                    markFolder('poor');
                    break;
                case 'n':
                    nextFolder();
                    break;
                case 's':
                    nextFolder();
                    break;
            }
        }
        // 加载文件夹
        async function loadFolder() {
            try {
                // 显示加载指示器
                loadingIndicator.style.display = 'block';
                folderListElement.innerHTML = '';
                // 使用文件系统API选择文件夹
                const directoryHandle = await window.showDirectoryPicker();
                // 重置数据
                markings = {};
                folderStructure = {};
                folderList = [];
                currentFolder = null;
                currentIndex = -1;
                // 读取文件夹结构
                await readDirectory(directoryHandle);
                // 构建文件夹列表
                buildFolderList();
                // 隐藏加载指示器
                loadingIndicator.style.display = 'none';
                // 如果有文件夹，选择第一个
                if (folderList.length > 0) {
                    selectFolder(0);
                }
            } catch (error) {
                console.error('Error loading folder:', error);
                loadingIndicator.style.display = 'none';
                if (error.name !== 'AbortError') {
                    alert('加载文件夹时出错: ' + error.message);
                }
            }
        }
        // 递归读取文件夹
        async function readDirectory(directoryHandle, path = '') {
            for await (const entry of directoryHandle.values()) {
                const entryPath = path ? `${path}/${entry.name}` : entry.name;
                if (entry.kind === 'directory') {
                    // 如果是文件夹，递归读取
                    folderStructure[entryPath] = {
                        name: entry.name,
                        path: entryPath,
                        files: []
                    };
                    await readDirectory(entry, entryPath);
                    // 如果文件夹中有HTML文件，添加到文件夹列表
                    if (folderStructure[entryPath].files.length >= 2) {
                        folderList.push(entryPath);
                    }
                } else if (entry.kind === 'file' && entry.name.endsWith('.html')) {
                    // 如果是HTML文件，添加到当前文件夹的文件列表
                    const folderPath = path || 'root';
                    if (!folderStructure[folderPath]) {
                        folderStructure[folderPath] = {
                            name: folderPath === 'root' ? '根目录' : folderPath.split('/').pop(),
                            path: folderPath,
                            files: []
                        };
                    }
                    folderStructure[folderPath].files.push({
                        name: entry.name,
                        handle: entry
                    });
                }
            }
        }
        // 构建文件夹列表
        function buildFolderList() {
            folderListElement.innerHTML = '';
            folderList = Object.keys(folderStructure).filter(path =>
                folderStructure[path].files.length >= 2
            );
            folderList.forEach((folderPath, index) => {
                const folder = folderStructure[folderPath];
                const li = document.createElement('li');
                li.className = 'folder-item';
                li.dataset.folder = folderPath;
                li.dataset.index = index;
                const status = markings[folderPath] || 'none';
                li.innerHTML = `
                    <span>${folder.name}</span>
                    <div class="folder-status status-${status}"></div>
                `;
                li.addEventListener('click', () => selectFolder(index));
                folderListElement.appendChild(li);
            });
            updateProgress();
        }
        // 选择文件夹
        async function selectFolder(index) {
            if (index < 0 || index >= folderList.length) return;
            currentIndex = index;
            currentFolder = folderList[index];
            currentFolderSpan.textContent = folderStructure[currentFolder].name;
            // 更新文件夹列表中的活动状态
            document.querySelectorAll('.folder-item').forEach(item => {
                item.classList.toggle('active', parseInt(item.dataset.index) === index);
            });
            // 显示文件夹中的文件
            const folder = folderStructure[currentFolder];
            const files = folder.files.slice(0, 2); // 只取前两个文件
            if (files.length >= 1) {
                fileName1.textContent = files[0].name;
                await displayFile(files[0].handle, preview1);
            } else {
                fileName1.textContent = '无文件';
                preview1.srcdoc = '<html><body><p>无文件可显示</p></body></html>';
            }
            if (files.length >= 2) {
                fileName2.textContent = files[1].name;
                await displayFile(files[1].handle, preview2);
            } else {
                fileName2.textContent = '无文件';
                preview2.srcdoc = '<html><body><p>无文件可显示</p></body></html>';
            }
            // 更新标记按钮状态
            updateMarkingButtons();
            updateProgress();
        }
        // 显示文件内容
        async function displayFile(fileHandle, iframe) {
            try {
                const file = await fileHandle.getFile();
                const content = await file.text();
                iframe.srcdoc = content;
            } catch (error) {
                console.error('Error reading file:', error);
                iframe.srcdoc = `<html><body><p>读取文件时出错: ${error.message}</p></body></html>`;
            }
        }
        // 更新标记按钮状态
        function updateMarkingButtons() {
            if (!currentFolder) return;
            const currentMark = markings[currentFolder];
            // 移除所有活动状态
            markGoodBtn.classList.remove('active');
            markFairBtn.classList.remove('active');
            markPoorBtn.classList.remove('active');
            // 添加当前标记的活动状态
            if (currentMark === 'good') markGoodBtn.classList.add('active');
            if (currentMark === 'fair') markFairBtn.classList.add('active');
            if (currentMark === 'poor') markPoorBtn.classList.add('active');
        }
        // 标记文件夹
        function markFolder(mark) {
            if (!currentFolder) {
                alert('请先选择一个文件夹');
                return;
            }
            markings[currentFolder] = mark;
            // 更新UI
            buildFolderList();
            updateMarkingButtons();
            // 自动跳转到下一个文件夹
            setTimeout(() => nextFolder(), 300);
        }
        // 下一个文件夹
        function nextFolder() {
            if (folderList.length === 0) return;
            // 查找下一个未标记的文件夹
            let nextIndex = currentIndex + 1;
            // 如果已经到达末尾，从头开始查找未标记的
            if (nextIndex >= folderList.length) {
                nextIndex = 0;
            }
            // 查找下一个未标记的文件夹
            let found = false;
            for (let i = nextIndex; i < folderList.length; i++) {
                if (!markings[folderList[i]]) {
                    selectFolder(i);
                    found = true;
                    break;
                }
            }
            // 如果从nextIndex开始没找到，从头开始找
            if (!found) {
                for (let i = 0; i < nextIndex; i++) {
                    if (!markings[folderList[i]]) {
                        selectFolder(i);
                        found = true;
                        break;
                    }
                }
            }
            // 如果所有文件夹都已标记，显示提示
            if (!found) {
                alert('所有文件夹都已标记完成！');
            }
        }
        // 更新进度
        function updateProgress() {
            const total = folderList.length;
            const marked = Object.keys(markings).length;
            const percentage = total > 0 ? (marked / total) * 100 : 0;
            progressBar.style.width = `${percentage}%`;
            progressText.textContent = `${marked}/${total}`;
        }
        // 导出结果
        function exportResults() {
            if (Object.keys(markings).length === 0) {
                alert('没有标记数据可导出');
                return;
            }
            // 创建导出数据
            const exportData = {
                timestamp: new Date().toISOString(),
                total_folders: folderList.length,
                marked_folders: Object.keys(markings).length,
                markings: markings
            };
            // 创建下载链接
            const dataStr = JSON.stringify(exportData, null, 2);
            const dataBlob = new Blob([dataStr], {type: 'application/json'});
            const link = document.createElement('a');
            link.href = URL.createObjectURL(dataBlob);
            link.download = `markings_${new Date().getTime()}.json`;
            link.click();
            alert('标记结果已导出');
        }
        // 初始化应用
        document.addEventListener('DOMContentLoaded', init);
    </script>
</body>
</html>
